"use client";

/**
 * Code Block
 * @registryDescription Syntax-highlighted code block for generated answers, terminal snippets, and compact examples.
 * @registryCategory display
 */

import * as React from "react";
import { CopyIcon, CheckIcon } from "@phosphor-icons/react";
import { cva, type VariantProps } from "class-variance-authority";
import { useShikiHighlight } from "@/hooks/use-shiki-highlight";
import { cn } from "@/lib/utils";

// ---- TYPES ------------------------------------------------------------------

interface CodeBlockProps
  extends React.ComponentProps<"div">, VariantProps<typeof codeBlockVariants> {
  /** Source code to display */
  code: string;
  /** Language for syntax highlighting. Default: "tsx" */
  language?: string;
  /** Whether to show line numbers. Default: false */
  showLineNumbers?: boolean;
  /** Whether to show the copy button. Default: true */
  showCopy?: boolean;
  /** Optional title / filename shown in header */
  title?: string;
  /** Maximum height before scrolling */
  maxHeight?: number | string;
}

// ---- VARIANTS ---------------------------------------------------------------

const codeBlockVariants = cva(
  "flex flex-col overflow-hidden rounded-xl ring-1 ring-border ring-inset text-sm font-mono",
  {
    variants: {
      size: {
        sm: "text-xs",
        md: "text-[13px]",
        lg: "text-sm",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// ---- COPY BUTTON ------------------------------------------------------------

function CopyButton({ code }: { code: string }) {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = React.useCallback(() => {
    navigator.clipboard.writeText(code).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  }, [code]);

  return (
    <button
      onClick={handleCopy}
      className="rounded-md p-1.5 text-muted-foreground/50 hover:text-foreground hover:bg-accent/60 transition-[background-color,color] duration-200 ease-out"
      aria-label={copied ? "Copied" : "Copy code"}
    >
      {copied ? (
        <CheckIcon className="size-3.5" />
      ) : (
        <CopyIcon className="size-3.5" />
      )}
    </button>
  );
}

// ---- COMPONENT --------------------------------------------------------------

function CodeBlock({
  code,
  language = "tsx",
  showLineNumbers = false,
  showCopy = true,
  title,
  maxHeight,
  size,
  className,
  ...props
}: CodeBlockProps) {
  const highlighted = useShikiHighlight(code, language);

  const normalizedCode = code || "";
  const lines = normalizedCode.split("\n");
  const lineCount =
    lines.length > 1 && lines[lines.length - 1] === ""
      ? lines.length - 1
      : lines.length;

  const gutterWidth = `${Math.max(2, String(lineCount).length)}ch`;

  const showHeader = title || showCopy;

  return (
    <div
      data-slot="code-block"
      className={cn(
        "bg-muted/40 dark:bg-muted/10",
        codeBlockVariants({ size }),
        className
      )}
      {...props}
    >
      {/* Header */}
      {showHeader && (
        <div className="flex shrink-0 items-center justify-between border-b border-border bg-muted/30 dark:border-border/30 dark:bg-muted/20 px-3 py-1.5">
          <div className="flex items-center gap-1.5">
            {title && (
              <span className="text-[12px] text-muted-foreground">{title}</span>
            )}
            {!title && (
              <span className="text-[11px] text-muted-foreground/50 uppercase tracking-wide">
                {language}
              </span>
            )}
          </div>
          <div className="flex items-center gap-1">
            {showCopy && <CopyButton code={normalizedCode} />}
          </div>
        </div>
      )}

      {/* Code area */}
      <div
        className="overflow-auto"
        style={
          maxHeight
            ? {
                maxHeight:
                  typeof maxHeight === "number" ? `${maxHeight}px` : maxHeight,
              }
            : undefined
        }
      >
        <div
          className={cn(
            "flex leading-5 transition-opacity duration-150",
            highlighted ? "opacity-100" : "opacity-40"
          )}
        >
          {/* Line numbers */}
          {showLineNumbers && (
            <div
              className="sticky left-0 z-10 shrink-0 select-none border-r border-border/40 dark:border-border/20 bg-muted/30 dark:bg-muted/10 px-2 py-3 text-right text-muted-foreground/40 dark:text-muted-foreground/30"
              style={{ minWidth: `calc(${gutterWidth} + 16px)` }}
              aria-hidden="true"
            >
              {Array.from({ length: lineCount }, (_, i) => (
                <div key={i} className="h-5">
                  {i + 1}
                </div>
              ))}
            </div>
          )}

          {/* Code content */}
          <div className="min-w-0 flex-1 p-3">
            {highlighted ? (
              <div className="[&_pre]:bg-transparent! [&_pre]:m-0! [&_pre]:p-0! [&_pre]:text-inherit! [&_pre]:leading-5! [&_code]:bg-transparent! [&_.shiki]:bg-transparent! [&_pre]:whitespace-pre!">
                {highlighted}
              </div>
            ) : (
              <pre className="m-0 whitespace-pre bg-transparent p-0 leading-5 text-foreground/80">
                <code>{normalizedCode}</code>
              </pre>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

CodeBlock.displayName = "CodeBlock";

export { CodeBlock, codeBlockVariants };
export type { CodeBlockProps };

"use client";


/**
 * useShikiHighlight
 * @registryDescription Client-side Shiki highlighting hook with lazy loading and JSX rendering.
 * @registryVariant audio
 */

import { useEffect, useState, type CSSProperties, type JSX } from "react";
import { toJsxRuntime } from "hast-util-to-jsx-runtime";
import { Fragment, jsx, jsxs } from "react/jsx-runtime";
import {
  preStyle,
  shikiOptionsForLang,
  type PreComponentProps,
} from "@/lib/shiki-config";

export type PreStyleVariant = "base" | "codeBlock" | "server" | "mapPreview";

interface UseShikiHighlightOptions {
  preVariant?: PreStyleVariant;
  skip?: boolean;
}

export function useShikiHighlight(
  code: string,
  lang: string,
  options: UseShikiHighlightOptions = {}
): JSX.Element | null {
  const { preVariant = "codeBlock", skip = false } = options;
  const [highlighted, setHighlighted] = useState<JSX.Element | null>(null);

  useEffect(() => {
    if (skip) return;

    let cancelled = false;

    async function highlight() {
      try {
        const { codeToHast } = await import("shiki");
        if (cancelled) return;

        const hast = await codeToHast(code.trim(), shikiOptionsForLang(lang));
        if (cancelled) return;

        const rendered = toJsxRuntime(hast, {
          Fragment,
          jsx,
          jsxs,
          components: {
            pre: ({ style, children, ...rest }: PreComponentProps) => (
              <pre
                {...rest}
                style={preStyle(preVariant, style as CSSProperties)}
              >
                {children}
              </pre>
            ),
          },
        }) as JSX.Element;

        setHighlighted(rendered);
      } catch {
        setHighlighted(null);
      }
    }

    void highlight();

    return () => {
      cancelled = true;
    };
  }, [code, lang, preVariant, skip]);

  return skip ? null : highlighted;
}

/**
 * Shiki Config
 * @registryDescription Shared Shiki theme and pre-style configuration for code highlighting.
 * @registryVariant audio
 */

import type { CSSProperties, ReactNode } from "react";
import type { BundledLanguage, BundledTheme } from "shiki";

export const SHIKI_THEMES = {
  light: "github-light" as BundledTheme,
  dark: "github-dark-dimmed" as BundledTheme,
};

export const SHIKI_OPTIONS = {
  themes: SHIKI_THEMES,
  defaultColor: false as const,
};

export function shikiOptionsForLang(lang: string) {
  return {
    lang: lang as BundledLanguage,
    ...SHIKI_OPTIONS,
  };
}

export const PRE_STYLES = {
  base: {
    margin: 0,
    background: "transparent",
    fontSize: "inherit",
    lineHeight: "inherit",
    whiteSpace: "pre",
    wordBreak: "normal",
    overflowWrap: "normal",
    maxWidth: "100%",
  } satisfies CSSProperties,

  codeBlock: {
    padding: "0.75rem",
  } satisfies CSSProperties,

  server: {
    padding: 0,
    overflow: "visible",
    tabSize: 2,
  } satisfies CSSProperties,

  mapPreview: {
    padding: "1rem",
    fontSize: "0.8125rem",
    lineHeight: "1.5",
  } satisfies CSSProperties,
} as const;

export function preStyle(
  variant: keyof typeof PRE_STYLES,
  existingStyle?: CSSProperties
): CSSProperties {
  if (variant === "base") {
    return { ...PRE_STYLES.base, ...existingStyle };
  }

  return { ...PRE_STYLES.base, ...PRE_STYLES[variant], ...existingStyle };
}

export type PreComponentProps = {
  style?: CSSProperties;
  children?: ReactNode;
  className?: string;
  [key: string]: unknown;
};
